namespace sv_aa675eb4696b4de6905b5eb7585d2221.Services;

public class WarehouseState
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName => Warehouses
        .FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public event Action? OnChange;

    public static IReadOnlyList<WarehouseInfo> Warehouses { get; } =
    [
        new("WH-001", "Warehouse A — East"),
        new("WH-002", "Warehouse B — West"),
        new("WH-003", "Warehouse C — Central"),
    ];

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public record WarehouseInfo(string Id, string Name);

namespace sv_aa675eb4696b4de6905b5eb7585d2221.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all subscribers.
/// Each circuit (user) gets its own instance, so warehouse selections are independent.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Fired when polling detects new alert data. All subscribed components should re-render.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component wants polling to run. Polling starts on first subscriber.
    /// </summary>
    public void Subscribe()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            StartPolling();
        }
    }

    /// <summary>
    /// Call when a component no longer needs polling. Polling stops when last subscriber leaves.
    /// </summary>
    public void Unsubscribe()
    {
        _subscriberCount--;
        if (_subscriberCount <= 0)
        {
            _subscriberCount = 0;
            StopPolling();
        }
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Immediate first poll
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;
                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task RefreshAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private void OnWarehouseChanged()
    {
        // When warehouse changes mid-poll, refresh immediately
        if (_subscriberCount > 0)
        {
            _ = RefreshAsync();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

