@inject Services.WarehouseState WarehouseState

<select class="form-select form-select-sm" value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseSelected" style="max-width: 220px;">
    @foreach (var wh in Services.WarehouseState.Warehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private void OnWarehouseSelected(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }
}

@inject Services.InventoryAlertService AlertService
@implements IDisposable

<span class="badge bg-danger rounded-pill">@AlertService.LowStockCount</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

