@page "/dashboard"
@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            <span class="badge bg-warning text-dark fs-5">@AlertService.LowStockCount</span>
        </p>
        <p class="text-muted small">Refreshes every 10 seconds while this page is visible.</p>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Subscribe to polling — starts the timer if this is the first subscriber
        AlertService.Subscribe();

        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;

        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _warehouseHandler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _alertHandler;
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.Unsubscribe();
    }
}

